#include<bits/stdc++.h>
using namespace std;
int sum[4005][4005],f[4005][4005],n,m,mod=10000;
int main(void){
	cin>>n>>m;
	f[0][0]=1;
	for(int i=0;i<=m;i++)sum[0][i]=1;
	for(int i=1;i<=n;i++){
		for(int j=0;j<=m;j++){
			f[i][j]=sum[i-1][j];
			if(j-i>=0)f[i][j]-=sum[i-1][j-i];
			sum[i][j]=f[i][j];
			if(j>0)sum[i][j]+=sum[i][j-1];
			f[i][j]%=mod,sum[i][j]%=mod;
		}
	}
	if(f[n][m]<0)f[n][m]+=mod;
	cout<<f[n][m];
	return false;
}
